    none_delete_pattern = re.compile('if\\s+val\\s+is\\s+None\\s+and\\s+var\\s+in\\s+os\\.environ\\s*:\\s*\\n\\s*del\\s+os\\.environ\\[var\\]', re.MULTILINE)
